import React, { useState, useEffect } from 'react';
import { getSeances, getMembersForSeance, markPresence } from '../services/api';

function Presence() {
  const [seances, setSeances] = useState([]);
  const [selectedSeance, setSelectedSeance] = useState('');
  const [membres, setMembres] = useState([]);
  const [presences, setPresences] = useState({});

  useEffect(() => {
    const fetchSeances = async () => {
      try {
        const res = await getSeances();
        setSeances(res.data);
      } catch (err) {
        console.error(err);
      }
    };
    fetchSeances();
  }, []);

  const loadPresence = async (id_seance) => {
    try {
      const res = await getPresence(id_seance);
      const presenceMap = {};
      res.data.forEach(p => {
        presenceMap[p.id_membre] = p.statut;
      });
      setPresences(presenceMap);
    } catch (err) {
      console.error(err);
    }
  };

  const handleSeanceChange = async (e) => {
    const id = e.target.value;
    setSelectedSeance(id);
    if (id) {
      loadPresence(id);
      try {
        const res = await getMembersForSeance();
        setMembres(res.data);
      } catch (err) {
        console.error(err);
      }
    }
  };

  const handleMark = async (id_membre, statut) => {
    try {
      await markPresence({ id_seance: selectedSeance, id_membre, statut });
      setPresences(prev => ({ ...prev, [id_membre]: statut }));
      alert('Présence enregistrée !');
    } catch (err) {
      alert('Erreur lors de l’enregistrement');
    }
  };

  return (
    <div className="container mt-4">
      <h2 className="mb-4 text-center">Suivi de Présence</h2>

      <div className="card mb-4">
        <div className="card-body">
          <label className="form-label">Sélectionner une séance</label>
          <select className="form-select" value={selectedSeance} onChange={handleSeanceChange}>
            <option value="">Choisir une séance</option>
            {seances.map(s => (
              <option key={s.id_seance} value={s.id_seance}>
                {s.date} à {s.heure} - {s.nom_sport || 'Sport inconnu'}
              </option>
            ))}
          </select>
        </div>
      </div>

      {selectedSeance && (
        <div className="table-responsive">
          <table className="table table-striped">
            <thead className="table-dark">
              <tr>
                <th>Nom</th>
                <th>Prénom</th>
                <th>Statut actuel</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {membres.map(m => (
                <tr key={m.id_personne}>
                  <td>{m.nom}</td>
                  <td>{m.prenom}</td>
                  <td>{presences[m.id_personne] || 'Non inscrit'}</td>
                  <td>
                    <button className="btn btn-success btn-sm me-2" onClick={() => handleMark(m.id_personne, 'Présent')}>
                      Présent
                    </button>
                    <button className="btn btn-danger btn-sm" onClick={() => handleMark(m.id_personne, 'Absent')}>
                      Absent
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default Presence;
